mapper.select:
SELECT NVL(a.ANNUAL_NO, 0) AS annualNo, e.EMP_NO AS empNo, NVL(a.BASE_YR, #{baseYr}) AS baseYr, NVL(a.TOT_ANNUAL_LV, 0) AS totAnnualLv, NVL(a.USED_ANNUAL_LV, 0) AS usedAnnualLv, NVL(a.REM_ANNUAL_LV, 0) AS remAnnualLv, NVL(a.SICK_LV, 0) AS sickLv, NVL(a.OFFICIAL_LV, 0) AS officialLv, NVL(a.REWARD_LV, 0) AS rewardLv, e.EMP_NM AS empNm, p.POS_NM AS posNm, d.DEPT_NM AS deptNm FROM EMP e JOIN POSITION_MST p ON e.POS_CD = p.POS_CD JOIN DEPT d ON e.DEPT_CD = d.DEPT_CD LEFT OUTER JOIN EMP_ANNUAL_LV a ON e.EMP_NO = a.EMP_NO AND a.BASE_YR = #{baseYr}
AND p.POS_NM = #{posNm}
AND ( e.EMP_NM LIKE '%' || #{search} || '%' OR e.EMP_NO LIKE '%' || #{search} || '%' OR p.POS_NM LIKE '%' || #{search} || '%' OR d.DEPT_NM LIKE '%' || #{search} || '%' )
ORDER BY e.EMP_NO

mapper.insert:
INSERT INTO EMP_ANNUAL_LV ( ANNUAL_NO, EMP_NO, BASE_YR, TOT_ANNUAL_LV, USED_ANNUAL_LV, SICK_LV, OFFICIAL_LV, REWARD_LV, REM_ANNUAL_LV ) SELECT SEQ_ANNUAL_NO.NEXTVAL, e.EMP_NO, #{baseYr}, #{totAnnualLv}, 0, 0, 0, 0, -- 신규 생성 시 잔여량은 총 연차와 동일 #{totAnnualLv} FROM EMP e JOIN POSITION_MST p ON e.POS_CD = p.POS_CD WHERE 1=1
AND p.POS_NM = #{posNm}
-- 핵심: 이미 데이터가 있는 사원은 제외 AND NOT EXISTS ( SELECT 1 FROM EMP_ANNUAL_LV a WHERE a.EMP_NO = e.EMP_NO AND a.BASE_YR = #{baseYr} )

mapper.update:
UPDATE EMP_ANNUAL_LV a SET a.TOT_ANNUAL_LV = #{totAnnualLv}, a.REM_ANNUAL_LV = (#{totAnnualLv} + a.REWARD_LV) - (a.USED_ANNUAL_LV + a.SICK_LV) WHERE a.BASE_YR = #{baseYr} AND a.EMP_NO IN ( SELECT e.EMP_NO FROM EMP e JOIN POSITION_MST p ON e.POS_CD = p.POS_CD WHERE 1=1
AND p.POS_NM = #{posNm}
)

